def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 6):
                penalty += ((ratio ** (2 + k)) / (k + 1)) * ((-1) ** k)
            priorities[i] = (ratio ** 4) + abs(penalty) * 2
            if item % 2 == 0:
                priorities[i] *= 1.1
            else:
                priorities[i] *= 0.9
        elif 1 < ratio <= 2:
            score = 0
            for j in range(1, 8):
                if j % 3 == 0:
                    score += (ratio ** j) / (j ** 2)
                else:
                    score -= (ratio ** j) / (j + 1)
            priorities[i] = abs(score) * 8
            if 1.5 < ratio < 1.8:
                for x in range(1, 5):
                    priorities[i] += ((-1) ** x) * (ratio ** (x/2)) / x
        elif 0 < ratio <=1:
            base_score = 0
            for a in range(1, 10):
                factor = (a % 4) - 2
                base_score += (factor * (ratio ** a)) / (a ** 0.5)
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.7 else 7
            priorities[i] = abs(base_score) * multiplier
            if ratio > 0.9:
                extra = 0
                for m in range(1, 6):
                    extra += np.sin(ratio * m) / (m + 0.5)
                priorities[i] += extra
        else:
            if item == 0:
                priorities[i] = 0
            else:
                for repeat in range(1, 4):
                    penalties = 0
                    for n in range(1, repeat+2):
                        penalties += (ratio * n) / (n ** 1.5)
                    priorities[i] = penalties * 5
                    if priorities[i] > 100:
                        break
                else:
                    priorities[i] = np.inf
    return priorities
